#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int k; cin >> k;
    unordered_map<int, int> count;
    for(int num : nums) count[num]++;
    vector<int> result;
    for(auto& pair : count) result.push_back(pair.first);
    sort(result.begin(), result.end(), [&](int a, int b) { return count[a] > count[b]; });
    result.resize(k);
    for(int num : result) cout << num << ' ';
    cout << '\n';
    return 0;
}
